--- 
+++ 
@@ -0,0 +1,751 @@
+/* ====================== GOOGLE FONT ====================== */
+
+@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700&display=swap');
+
+/* ====================== GLOBAL ====================== */
+
+html {
+    scroll-behavior: smooth;
+}
+
+*{
+    box-sizing:border-box;
+}
+
+body {
+    font-family:'Poppins', sans-serif;
+    margin:5px;
+    background:#f5f7fb;
+    color:#1e293b;
+    overflow-x:hidden;
+}
+
+img,
+table {
+    max-width:100%;
+}
+
+h2 {
+    text-align:center;
+}
+
+/* ====================== CONTROLS ====================== */
+.controls-top {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    gap: 15px;
+    flex-wrap: wrap;
+}
+
+/* TAB CONTAINER */
+.day-tabs {
+    display: flex;
+    gap: 10px;
+}
+.active {
+    background: #1e3a8a;
+    color: white;
+}
+/* TAB BUTTON STYLE */
+.day-tab {
+    padding: 10px 14px;
+    border: none;
+    border-radius: 10px;
+    cursor: pointer;
+
+    background: #e2e8f0;
+    color: #f4f4f4;
+    font-weight: 600;
+
+    transition: 0.2s ease;
+}
+
+/* ACTIVE TAB */
+.day-tab.active {
+    background: #1e3a8a;
+    color: white;
+}
+
+/* HOVER */
+.day-tab:hover {
+    background: #2563eb;
+    color: white;
+}
+.controls {
+
+    display:flex;
+    justify-content:center;
+    align-items:center;
+    gap:12px;
+    flex-wrap:wrap;
+    margin-bottom:20px;
+
+    background:transparent;
+    padding:18px;
+    border-radius:16px;
+    color: white;
+}
+
+.controls input[type="file"]{
+
+    padding:10px;
+    border:2px dashed #2563eb;
+    border-radius:10px;
+    background:#eff6ff;
+    cursor:pointer;
+
+    max-width:100%;
+}
+
+.controls button{
+
+    padding:10px 18px;
+    border:none;
+    border-radius:10px;
+
+    background:#1e3a8a;
+    color:white;
+
+    font-weight:600;
+    cursor:pointer;
+
+    transition:0.2s ease;
+}
+
+.controls button:hover{
+
+    background:#2563eb;
+    transform:translateY(-2px);
+
+}
+
+/* ================= MAIN CONTAINER ================= */
+
+#seat-container {
+    width:100%;
+    padding-top:50px;
+    background-color:#ffffff;
+    overflow-x:auto;
+    overflow-y:hidden;
+    -webkit-overflow-scrolling:touch;
+}
+
+/* IMPORTANT: allow content to expand */
+
+#output {
+    display:inline-block;
+    width:max-content;
+    min-width:100%;
+    text-align:center;
+}
+
+/* ================= INFO CARD ================= */
+
+.info-card {
+
+    display:inline-block;
+    vertical-align:top;
+    width:1500px;
+    max-width:100%;
+
+    margin-top:20px;
+
+    padding:20px;
+    border-radius:18px;
+
+    background:#ffffff;
+
+    border:1px solid #e2e8f0;
+
+    box-shadow:0 8px 25px rgba(0,0,0,0.06);
+    margin-bottom:30px;
+}
+
+.info-card h3 {
+
+    margin-bottom:18px;
+    font-size:20px;
+    font-weight:700;
+
+    color:#1e3a8a;
+}
+
+.info-row {
+
+    display:flex;
+    justify-content:space-between;
+    gap:20px;
+
+    padding:12px 0;
+
+    border-bottom:1px solid #f1f5f9;
+}
+
+.info-row:last-child {
+    border-bottom:none;
+}
+
+.label {
+
+    font-size:12px;
+    color:#64748b;
+
+    text-transform:uppercase;
+    letter-spacing:1px;
+}
+
+.value {
+
+    font-size:14px;
+    font-weight:600;
+    color:#0f172a;
+
+    text-align:right;
+    word-break:break-word;
+}
+#scroll-note {
+    width: 100%;
+    max-width: 100%;
+
+    background: rgba(15, 23, 42, 0.95);
+    color: white;
+
+    text-align: center;
+    padding: 10px 12px;
+
+    font-size: 13px;
+    font-weight: 500;
+
+    border-top: 1px solid #334155;
+
+    margin-top: 8px;
+}
+/* ====================== STAGE & GRANDSTAND ====================== */
+
+.stage {
+
+    background:#1e3a8a;
+    color:white;
+
+    padding:14px;
+
+    margin:15px auto;
+
+    text-align:center;
+    font-weight:700;
+
+    width:300px;
+    max-width:95%;
+
+    border-radius:14px;
+
+    box-shadow:0 8px 20px rgba(30,58,138,0.25);
+}
+
+.grandstand {
+
+    background:#0f172a;
+    color:white;
+
+    padding:14px;
+
+    margin:15px auto;
+
+    text-align:center;
+    font-weight:700;
+
+    width:600px;
+    max-width:95%;
+
+    border-radius:14px;
+
+    box-shadow:0 8px 20px rgba(15,23,42,0.25);
+}
+
+/* ====================== SEAT LAYOUT ====================== */
+
+.seat-wrapper {
+
+    display:flex;
+    flex-wrap:nowrap;
+
+    gap:20px;
+    width:max-content;
+}
+
+.cluster-box {
+
+    margin:20px 10px;
+    width:1110px;
+    padding:20px;
+    flex-shrink:0;
+}
+
+/* KEEP ORIGINAL GRID */
+
+.grid {
+
+    display:grid;
+
+    grid-template-columns:repeat(40, 25px);
+
+    grid-auto-rows:25px;
+
+    gap:2px;
+
+    width:max-content;
+}
+
+/* KEEP ORIGINAL SEAT SIZE */
+
+.seat {
+
+    width:25px;
+    height:25px;
+
+    background:#e0e7ff;
+
+    border-radius:4px;
+
+    cursor:pointer;
+
+    display:flex;
+    align-items:center;
+    justify-content:center;
+
+    transition:0.2s ease;
+
+    flex-shrink:0;
+}
+
+.seat:hover {
+
+    background:#60a5fa;
+    transform:scale(1.08);
+}
+
+.seat.selected {
+
+    background:#2563eb !important;
+    color:white;
+}
+
+.seat-code {
+
+    font-size:9px;
+    font-weight:600;
+}
+
+/* EXECUTIVE */
+
+.seat.executive {
+
+    background:#87CEFA !important;
+    color:#000 !important;
+}
+
+/* ====================== TABLE ====================== */
+
+.table-container {
+
+    margin-top:20px;
+
+    padding:20px;
+
+    border-radius:18px;
+
+    background:#fff;
+
+    box-shadow:0 8px 25px rgba(0,0,0,0.06);
+
+    width:100%;
+    overflow:hidden;
+}
+
+/* ====================== MODERN TABLE HEADER ====================== */
+
+.table-header {
+
+    display:flex;
+
+    justify-content:space-between;
+
+    align-items:center;
+
+    gap:15px;
+
+    padding:14px 18px;
+
+    border-radius:16px;
+
+    background:linear-gradient(
+        135deg,
+        #1e3a8a,
+        #2563eb
+    );
+
+    margin-bottom:18px;
+
+    flex-wrap:wrap;
+}
