commits.content:
/* ====================== GOOGLE FONT ====================== */

@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700&display=swap');

/* ====================== GLOBAL ====================== */

html {
    scroll-behavior: smooth;
}

*{
    box-sizing:border-box;
}

body {
    font-family:'Poppins', sans-serif;
    margin:5px;
    background:#f5f7fb;
    color:#1e293b;
    overflow-x:hidden;
}

img,
table {
    max-width:100%;
}

h2 {
    text-align:center;
}

/* ====================== CONTROLS ====================== */
.controls {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 12px;
    flex-wrap: wrap;
    margin-bottom: 20px;

    background: white;
    padding: 18px;
    border-radius: 16px;

    box-shadow: 0 6px 20px rgba(0,0,0,0.06);
}

/* LEFT */
.controls-left h2 {
    margin: 0;
    font-size: 24px;
}

/* RIGHT */
.controls-right {
    display: flex;
    align-items: center;
    gap: 12px;
    flex-wrap: wrap;
}

/* MOBILE */
@media (max-width: 768px) {
    .controls {
        flex-direction: column;
        align-items: flex-start;
    }

    .controls-right {
        width: 100%;
    }
}

.controls input[type="file"]{

    padding:10px;
    border:2px dashed #2563eb;
    border-radius:10px;
    background:#eff6ff;
    cursor:pointer;

    max-width:100%;
}

.controls button{

    padding:10px 18px;
    border:none;
    border-radius:10px;

    background:#1e3a8a;
    color:white;

    font-weight:600;
    cursor:pointer;

    transition:0.2s ease;
}

.controls button:hover{

    background:#2563eb;
    transform:translateY(-2px);

}

/* ================= MAIN CONTAINER ================= */

#seat-container {
    width:100%;
    padding-top:50px;
    background-color:#ffffff;
    overflow-x:auto;
    overflow-y:hidden;
    -webkit-overflow-scrolling:touch;
}

/* IMPORTANT: allow content to expand */

#output {
    display:inline-block;
    width:max-content;
    min-width:100%;
    text-align:center;
}

/* ================= INFO CARD ================= */

.info-card {

    display:inline-block;
    vertical-align:top;
    width:1500px;
    max-width:100%;

    margin-top:20px;

    padding:20px;
    border-radius:18px;

    background:#ffffff;

    border:1px solid #e2e8f0;

    box-shadow:0 8px 25px rgba(0,0,0,0.06);
    margin-bottom:30px;
}

.info-card h3 {

    margin-bottom:18px;
    font-size:20px;
    font-weight:700;

    color:#1e3a8a;
}

.info-row {

    display:flex;
    justify-content:space-between;
    gap:20px;

    padding:12px 0;

    border-bottom:1px solid #f1f5f9;
}

.info-row:last-child {
    border-bottom:none;
}

.label {

    font-size:12px;
    color:#64748b;

    text-transform:uppercase;
    letter-spacing:1px;
}

.value {

    font-size:14px;
    font-weight:600;
    color:#0f172a;

    text-align:right;
    word-break:break-word;
}
#scroll-note {
    width: 100%;
    max-width: 100%;

    background: rgba(15, 23, 42, 0.95);
    color: white;

    text-align: center;
    padding: 10px 12px;

    font-size: 13px;
    font-weight: 500;

    border-top: 1px solid #334155;

    margin-top: 8px;
}
/* ====================== STAGE & GRANDSTAND ====================== */

.stage {

    background:#1e3a8a;
    color:white;

    padding:14px;

    margin:15px auto;

    text-align:center;
    font-weight:700;

    width:300px;
    max-width:95%;

    border-radius:14px;

    box-shadow:0 8px 20px rgba(30,58,138,0.25);
}

.grandstand {

    background:#0f172a;
    color:white;

    padding:14px;

    margin:15px auto;

    text-align:center;
    font-weight:700;

    width:600px;
    max-width:95%;

    border-radius:14px;

    box-shadow:0 8px 20px rgba(15,23,42,0.25);
}

/* ====================== SEAT LAYOUT ====================== */

.seat-wrapper {

    display:flex;
    flex-wrap:nowrap;

    gap:20px;
    width:max-content;
}

.cluster-box {

    margin:20px 10px;
    width:1110px;
    padding:20px;
    flex-shrink:0;
}

/* KEEP ORIGINAL GRID */

.grid {

    display:grid;

    grid-template-columns:repeat(40, 25px);

    grid-auto-rows:25px;

    gap:2px;

    width:max-content;
}

/* KEEP ORIGINAL SEAT SIZE */

.seat {

    width:25px;
    height:25px;

    background:#e0e7ff;

    border-radius:4px;

    cursor:pointer;

    display:flex;
    align-items:center;
    justify-content:center;

    transition:0.2s ease;

    flex-shrink:0;
}

.seat:hover {

    background:#60a5fa;
    transform:scale(1.08);
}

.seat.selected {

    background:#2563eb !important;
    color:white;
}

.seat-code {

    font-size:9px;
    font-weight:600;
}

/* EXECUTIVE */

.seat.executive {

    background:#87CEFA !important;
    color:#000 !important;
}

/* ====================== TABLE ====================== */

.table-container {

    margin-top:20px;

    padding:20px;

    border-radius:18px;

    background:#fff;

    box-shadow:0 8px 25px rgba(0,0,0,0.06);

    width:100%;
    overflow:hidden;
}

/* ====================== MODERN TABLE HEADER ====================== */

.table-header {

    display:flex;

    justify-content:space-between;

    align-items:center;

    gap:15px;

    padding:14px 18px;

    border-radius:16px;

    background:linear-gradient(
        135deg,
        #1e3a8a,
        #2563eb
    );

    margin-bottom:18px;

    flex-wrap:wrap;
}

.table-header h3 {

    margin:0;

    font-size:20px;

    font-weight:700;

    color:white;
}

/* CONTROLS */

.table-header .table-controls {

    display:flex;

    gap:10px;

    align-items:center;
    flex-wrap:wrap;
}

/* INPUTS */

.table-header select,
.table-header input {

    padding:10px 12px;

    border:none;

    border-radius:10px;

    font-size:14px;

    outline:none;

    background:white;

    transition:0.2s ease;

    max-width:100%;
}

.table-header input {

    width:220px;
}

.table-header select:focus,
.table-header input:focus {

    box-shadow:0 0 0 4px rgba(255,255,255,0.25);
}

/* ====================== TABLE ====================== */

.table-scroll{
    width:100%;
    overflow-x:auto;
    -webkit-overflow-scrolling:touch;
}

#student-list {

    width:100%;

    min-width:700px;

    border-collapse:collapse;

    overflow:hidden;

    border-radius:14px;
}

#student-list th,
#student-list td {

    padding:14px;

    font-size:14px;

    border-bottom:1px solid #e2e8f0;

    text-align:left;
}

/* TABLE HEAD */

#student-list th {

    background:#1e293b;

    color:white;

    font-weight:600;

    white-space:nowrap;
}

/* ROW HOVER */

#student-list tbody tr {

    transition:0.2s ease;
}

#student-list tbody tr:hover {

    background:#eff6ff;
}

/* ====================== CLUSTER HEADER ====================== */

.cluster-header td {

    background:#1e3a8a !important;

    color:white;

    font-size:14px;

    font-weight:700;

    letter-spacing:1px;

    text-transform:uppercase;
}

/* ====================== BUTTONS ====================== */

td button {

    border:none;

    padding:8px 12px;

    border-radius:8px;

    cursor:pointer;

    font-size:13px;

    font-weight:600;

    transition:0.2s ease;

    white-space:nowrap;
}

/* VIEW */

td button:first-child {

    background:#2563eb;
    color:white;
}

td button:first-child:hover {

    background:#1d4ed8;
}

/* DELETE */

td button:last-child {

    background:#ffffff;
    color:black;
}

td button:last-child:hover {

    background:#ff9898;
}


/* ERASE ALL DATA */
.danger-btn {
    background: #ef4444 !important;
    color: white;
    border: none;
    padding: 10px 18px;
    border-radius: 10px;
    font-weight: 600;
    cursor: pointer;
    transition: 0.2s ease;
}

.danger-btn:hover {
    background: #dc2626;
    transform: translateY(-2px);
}
/* ====================== SEARCH BOX ====================== */

.search-box {

    text-align:center;

    margin:10px 0;
}

#searchInput {

    width:300px;
    max-width:100%;
}

/* ====================== RESPONSIVE ====================== */

@media (max-width:992px){

    .controls{
        justify-content:center;
    }

    .table-header{
        flex-direction:column;
        align-items:stretch;
    }

    .table-header .table-controls{
        width:100%;
        justify-content:stretch;
    }

    .table-header select,
    .table-header input{
        flex:1;
    }

    .info-card{
        width:100%;
    }
}

@media (max-width:768px) {

    body{
        margin:8px;
    }

    .controls {

        flex-direction:column;
        align-items:stretch;
    }

    .controls button,
    .controls input[type="file"]{
        width:100%;
    }

    .stage{
        width:100%;
    }

    .grandstand{
        width:100%;
    }

    .table-container {
        padding:14px;
    }

    .table-header {

        flex-direction:column;

        align-items:stretch;

        gap:12px;
    }

    .table-header h3 {

        text-align:left;

        font-size:18px;
    }

    .table-header .table-controls {

        flex-direction:column;

        width:100%;
    }

    .table-header select,
    .table-header input {

        width:100%;
    }

    .search-box {

        width:100%;

        margin:0;
    }

    #searchInput {
        width:100%;
    }

    .info-card {

        width:100%;
        padding:16px;
    }

    .info-row {

        flex-direction:column;

        align-items:flex-start;

        gap:5px;
    }

    .info-row .value {

        text-align:left;

        margin-top:2px;
    }
}

@media (max-width:600px) {

    h2{
        font-size:20px;
    }

    .table-header h3 {

        font-size:16px;
    }

    #student-list th,
    #student-list td{

        padding:10px;
        font-size:12px;
    }

    td button{

        width:100%;
        margin-bottom:5px;
    }

    .cluster-box{
        padding:12px;
    }
}
